import{_ as o,o as a,c as i,aA as r}from"./chunks/framework.DlYq8M-n.js";const h=JSON.parse('{"title":"Performance Tips","description":"","frontmatter":{},"headers":[],"relativePath":"perf.md","filePath":"perf.md","lastUpdated":null}'),t={name:"perf.md"};function n(d,e,l,c,s,p){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="Performance-Tips" tabindex="-1">Performance Tips <a class="header-anchor" href="#Performance-Tips" aria-label="Permalink to &quot;Performance Tips {#Performance-Tips}&quot;">​</a></h1><h2 id="Avoid-Scalar-Indexing" tabindex="-1">Avoid Scalar Indexing <a class="header-anchor" href="#Avoid-Scalar-Indexing" aria-label="Permalink to &quot;Avoid Scalar Indexing {#Avoid-Scalar-Indexing}&quot;">​</a></h2><p>Accessing elements of an NDArray one at a time (e.g., <code>arr[5]</code>) is slow and should be avoided. Indexing like this requires data to be trasfered between device and host and maybe even communicated across nodes. Scalar indexing will emit an error which can be opted out of with <code>@allowscalar</code> or <code>allwoscalar() do ... end</code>. Several functions in the existing API invoke scalar indexing and are intended for testing (e.g., the <code>==</code> operator).</p><h2 id="Avoid-Implicit-Promotion" tabindex="-1">Avoid Implicit Promotion <a class="header-anchor" href="#Avoid-Implicit-Promotion" aria-label="Permalink to &quot;Avoid Implicit Promotion {#Avoid-Implicit-Promotion}&quot;">​</a></h2><p>Mixing integral types of different size (e.g., <code>Float64</code> and <code>Float32</code>) will result in implicit promotion of the smaller type to the larger types. This creates a copy of the data and hurts performance. Implicit promotion from a smaller integral type to a larger integral type will emit an error which can be opted out of with <code>@allowpromotion</code> or <code>allowpromotion() do ... end</code>. This error is common when mixing literals with <code>NDArrays</code>. By default a floating point literal (i.e., 1.0) is <code>Float64</code> but the default type of an <code>NDArray</code> is <code>Float32</code>.</p><h2 id="Kernel-Fusion" tabindex="-1">Kernel Fusion <a class="header-anchor" href="#Kernel-Fusion" aria-label="Permalink to &quot;Kernel Fusion {#Kernel-Fusion}&quot;">​</a></h2><p>cuPyNumeric does not fuse independent operations automatically, even in broadcast expressions. This is a priority for a future release.</p>',7)])])}const f=o(t,[["render",n]]);export{h as __pageData,f as default};
